  // 图表类型：图片（IMAGE）
  // 别名/同义词：图片卡、图片展示、图片轮播、Banner 图
  // 用途：在仪表盘中展示一张或多张静态图片，支持多图轮播（滑动/淡入淡出），
  //       可为每张图片配置标题、描述和点击跳转链接。适合展示品牌 Banner、
  //       产品图、说明图、装饰图等不依赖数据表的纯图片内容。
  // 重要：当用户说"图片"、"图片卡"、"图片展示"、"Banner"、"轮播图"时，
  //       必须使用 chartType = "IMAGE"，不要使用其他图表类型。
  //       此图表类型不依赖数据表，无需配置 sheet / view / filter。
  // ═══════════════════════════════════════════════════════════════════
  "IMAGE": {
    // 必填，图表类型，固定值 "IMAGE"（图片）
    "chartType": "IMAGE",
    // 必填，卡片标题，用户在仪表盘中看到的图表名称，应准确且见名知意
    "name": "图片",
    // 必填，图片列表，至少包含一张图片；多张图片时支持轮播
    "img_images": [
      {
        // 必填，图片的访问 URL
        "url": "https://example.com/image.png",
        // 可选，图片标题，显示在图片上方（需 img_showImgText=true）
        "title": "",
        // 可选，图片描述，显示在标题下方（需 img_showImgText=true）
        "desc": "",
        // 可选，点击图片后跳转的链接 URL
        "toUrl": "",
        // 必填，图片填充模式，合法值：cover（裁剪铺满）/ contain（等比缩放留白）/ fill（拉伸铺满）
        "fillMode": "cover"
      }
    ],
    // 可选，是否在图片上显示标题和描述文字，默认 true；
    // 设为 false 时 img_titleStyle / img_descStyle / img_textAlign 均不生效
    "img_showImgText": true,
    // 可选，图片文字的对齐位置，合法值：
    //   leftTop / top / rightTop / left / center / right / leftBottom / bottom / rightBottom
    "img_textAlign": "center",
    // 可选，图片标题的字体样式（仅 img_showImgText=true 时生效）
    "img_titleStyle": {
      // 字体大小（px），合法范围 16~56，步长 4
      "size": 16,
      // 字体颜色，十六进制色值，如 "#FFFFFF"
      "color": "",
      // 是否加粗
      "bold": true,
      // 是否斜体
      "italic": false,
      // 是否下划线
      "underline": false
    },
    // 可选，图片描述的字体样式（仅 img_showImgText=true 时生效）
    "img_descStyle": {
      // 字体大小（px），合法范围 16~56，步长 4
      "size": 14,
      // 字体颜色，十六进制色值
      "color": "",
      // 是否加粗
      "bold": false,
      // 是否斜体
      "italic": false,
      // 是否下划线
      "underline": false
    },
    // 可选，多图时是否自动轮播，默认 false；单张图片时此配置无效
    "img_autoPlay": false,
    // 可选，多图轮播切换动效，合法值：slide（滑动）/ fade（淡入淡出），默认 slide；单张图片时无效
    "img_imgTransitionType": "slide",
    // 可选，多图自动轮播间隔（秒），合法范围 0.1~1000，默认 1；仅 img_autoPlay=true 时生效
    "img_imgTransitionInterval": 1
