    "chartType": "PROGRESS",
    // ⚠️ 必填，统计类型，进度图固定为 "record-count"
    "measureType": "record-count",
    // ⚠️ 必填，顶层数据表 ID，设置为 currentSheet 相同的值
    "sheet": "<sheetId>",
    // ⚠️ 必填，顶层视图 ID，设置为空字符串
    "view": "",
    // ⚠️ 必填，顶层筛选条件，设置为空数组
    "filter": [],

