    "name": "进度图",
    // 必填，数据类型，合法值：number（数值进度）/ date（日期进度）
    "dataType": "number",
    // 必填，图表形状，合法值：bar（条形）/ semi-circle（半环）/ circle（圆环）
    "progressType": "bar",

    // ── 目标值配置 ──────────────────────────────────────────────────────────
    // 目标值来源，合法值：custom（自定义数值）/ sheet（从数据表字段聚合）
    "targetSource": "custom",
    // targetSource = "custom" 时填写，目标值的固定数值字符串
    "target": "500",
    // 必填，目标值来源的数据表 ID，即使 targetSource = "custom" 也要填写，设置为 currentSheet 相同的值
    "targetSheet": "<sheetId>",
    // 必填，目标值来源的视图 ID，设置为空字符串
    "targetView": "",
